+const GROQ_ENDPOINT = "https://api.groq.com/openai/v1/chat/completions";
+const DEFAULT_MODEL = "llama-3.1-8b-instant";
+
+chrome.action.onClicked.addListener(async (tab) => {
+  if (!tab.id) return;
+  chrome.tabs.sendMessage(tab.id, { type: "TOGGLE_SIDEBAR" });
+});
+
+chrome.runtime.onMessage.addListener((message, _sender, sendResponse) => {
+  if (message?.type !== "ASK_GROQ") return;
+
+  askGroq(message.payload)
+    .then((answer) => sendResponse({ ok: true, answer }))
+    .catch((error) => sendResponse({ ok: false, error: error.message }));
+
+  return true;
+});
+
+async function askGroq(payload) {
+  const { apiKey } = await chrome.storage.sync.get(["apiKey"]);
+  if (!apiKey) {
+    throw new Error("Groq API key missing. Set it in extension options.");
+  }
+
+  const { question, visibleText } = payload || {};
+  if (!question?.trim()) {
+    throw new Error("Question is empty.");
+  }
+
+  const context = (visibleText || "").trim();
+  if (context.length < 80) {
+    throw new Error("Not enough visible text. Scroll the page and try again.");
+  }
+
+  const body = {
+    model: DEFAULT_MODEL,
+    temperature: 0.2,
+    messages: [
+      {
+        role: "system",
+        content:
+          "You answer questions using only the provided visible page text. If the answer is not present, say you do not have enough visible context."
+      },
+      {
+        role: "user",
+        content: `VISIBLE PAGE TEXT:\n${context}\n\nQUESTION:\n${question}`
+      }
+    ]
+  };
+
+  const resp = await fetch(GROQ_ENDPOINT, {
+    method: "POST",
+    headers: {
+      "Content-Type": "application/json",
+      Authorization: `Bearer ${apiKey}`
+    },
+    body: JSON.stringify(body)
+  });
+
+  if (!resp.ok) {
+    const errText = await resp.text();
+    throw new Error(`Groq error (${resp.status}): ${errText}`);
+  }
+
+  const data = await resp.json();
+  return data?.choices?.[0]?.message?.content?.trim() || "No answer returned.";
+}
