+    choices = [],
+    visibleText,
+    pageText,
+    pageTitle,
+    pageUrl
+  } = payload || {};
+
+  const visibleContext = (visibleText || "").trim();
+  const fallbackContext = (pageText || "").trim();
+  const context = visibleContext.length >= 120 ? visibleContext : fallbackContext;
+  if (context.length < 120) {
+    throw new Error("Not enough page context to answer. Scroll and try again.");
+  }
+
+  const normalizedChoices = Array.isArray(choices)
+    ? choices
+        .map((c) => ({
+          choiceId: String(c.choiceId || ""),
+          text: String(c.text || "").trim()
+        }))
+        .filter((c) => c.choiceId && c.text)
+    : [];
+
+  const mustClick = task === "mcq" && normalizedChoices.length > 1;
+  const mustType = task === "text";
+
+  const schemaHint = mustClick
+    ? `Return JSON: {"action":"click","choiceId":"<one of: ${normalizedChoices
+        .map((c) => c.choiceId)
+        .join(", ")}>","confidence":0.0,"reason":"..." }`
+    : mustType
+      ? `Return JSON: {"action":"type","text":"...","confidence":0.0,"reason":"..."}`
+      : `Return JSON: {"action":"refuse","confidence":0.0,"reason":"..."} or click/type as appropriate.`;
+
+  const userPayload = [
+    `PAGE TITLE: ${pageTitle || "Unknown"}`,
+    `PAGE URL: ${pageUrl || "Unknown"}`,
+    "",
+    "QUESTION BLOCK:",
+    questionText || "",
+    "",
+    mustClick ? "CHOICES:" : "",
+    mustClick ? normalizedChoices.map((c) => `- ${c.choiceId}: ${c.text}`).join("\n") : "",
+    "",
+    "VISIBLE CONTEXT (preferred):",
+    visibleContext || "(none)",
+    "",
+    "PAGE CONTEXT (fallback):",
+    fallbackContext || "(none)",
+    "",
+    "INSTRUCTIONS:",
+    `- Output ONLY valid JSON, no markdown.`,
+    `- Choose the best single answer based on the context.`,
+    `- confidence is 0..1.`,
+    `- If unsure, action="refuse".`,
+    schemaHint
+  ]
+    .filter(Boolean)
+    .join("\n");
+
+  const body = {
+    model: DEFAULT_MODEL,
+    temperature: 0.1,
+    messages: [
+      {
+        role: "system",
+        content:
+          "You are an automation planner. Output ONLY valid JSON. Never include any extra keys beyond action/choiceId/text/confidence/reason."
+      },
+      { role: "user", content: userPayload }
+    ]
+  };
+
+  const resp = await fetch(GROQ_ENDPOINT, {
+    method: "POST",
+    headers: {
+      "Content-Type": "application/json",
+      Authorization: `Bearer ${apiKey}`
+    },
+    body: JSON.stringify(body)
+  });
+
+  if (!resp.ok) {
+    const errText = await resp.text();
+    throw new Error(`Groq error (${resp.status}): ${errText}`);
+  }
+
+  const data = await resp.json();
+  const raw = data?.choices?.[0]?.message?.content?.trim() || "";
+  const plan = safeParseJson(raw);
+  if (!plan) {
+    throw new Error(`Model did not return valid JSON. Raw: ${raw.slice(0, 200)}`);
+  }
+
+  const cleaned = {
+    action: plan.action,
+    choiceId: plan.choiceId,
+    text: plan.text,
+    confidence: typeof plan.confidence === "number" ? plan.confidence : 0,
+    reason: typeof plan.reason === "string" ? plan.reason : ""
+  };
+
+  if (!["click", "type", "refuse"].includes(cleaned.action)) {
+    cleaned.action = "refuse";
+    cleaned.reason = cleaned.reason || "Invalid action.";
+  }
+
+  if (mustClick) {
+    const ids = new Set(normalizedChoices.map((c) => c.choiceId));
+    if (cleaned.action !== "click" || !ids.has(String(cleaned.choiceId || ""))) {
+      return { action: "refuse", confidence: 0, reason: "No valid choice selected." };
+    }
+  }
+
+  if (mustType) {
+    if (cleaned.action !== "type" || !String(cleaned.text || "").trim()) {
+      return { action: "refuse", confidence: 0, reason: "No text answer provided." };
+    }
+  }
+
+  return cleaned;
+}
+
+function safeParseJson(raw) {
+  try {
+    return JSON.parse(raw);
+  } catch {}
+  const start = raw.indexOf("{");
+  const end = raw.lastIndexOf("}");
+  if (start === -1 || end === -1 || end <= start) return null;
+  const slice = raw.slice(start, end + 1);
+  try {
+    return JSON.parse(slice);
+  } catch {
+    return null;
+  }
